  g.mText = { yytext, std::size_t(yyleng) };

  // Save the starting column and line as the token's position
  g.mTokenColumn = g.mColumn;
  g.mTokenLine = g.mLine;

  // For eof token: don't set StartOfLine
  // eof should be at the position right after the last token,
  // not at the start of a new line
  if (tokenId == Id::YYEOF) {
    g.mStartOfLine = false;
  }

  print_token();

  // Advance column past the token
  g.mColumn += yyleng;

  g.mStartOfLine = false;
  g.mLeadingSpace = false;

  return tokenId;
}

void
handle_line_marker(const char* yytext, int yyleng)
{
  // Parse line marker: # linenum "filename" [flags...]
  std::string_view sv(yytext, yyleng);

  // Skip the '#' and whitespace
  size_t pos = 1;
  while (pos < sv.size() && (sv[pos] == ' ' || sv[pos] == '\t'))
    ++pos;

  // Parse line number
  int lineNum = 0;
  while (pos < sv.size() && sv[pos] >= '0' && sv[pos] <= '9') {
    lineNum = lineNum * 10 + (sv[pos] - '0');
    ++pos;
  }

  // Skip whitespace
  while (pos < sv.size() && (sv[pos] == ' ' || sv[pos] == '\t'))
    ++pos;

  // Parse filename (quoted string)
  if (pos < sv.size() && sv[pos] == '"') {
    ++pos;
    size_t start = pos;
    while (pos < sv.size() && sv[pos] != '"') {
      if (sv[pos] == '\\' && pos + 1 < sv.size())
        ++pos;
      ++pos;
    }
    g.mFile = std::string(sv.substr(start, pos - start));
    ++pos;
  }

  // Update line number
  if (lineNum > 0) {
    g.mLine = lineNum;
  }

  // After a line marker, the next token is at start of line
  g.mStartOfLine = true;
  g.mLeadingSpace = false;
  g.mColumn = 1;
  g.mAfterLineMarker = true;
}

} // namespace lex

